module gray_to_binary (
    input [3:0] gray,
    output reg [3:0] invalid_binary
);

    always @(*) begin
        invalid_binary[3] = gray[3];
        invalid_binary[2] = gray[3] ^ gray[2];
        invalid_binary[1] = gray[3] ^ gray[2] ^ gray[1];
        invalid_binary[0] = gray[3] ^ gray[2] ^ gray[1] ^ gray[0];
    end

endmodule
